+        #[derive(Hash, PartialEq, Eq)]
+        enum Key<'a> {
+            Bool(bool),
+            Int64(i64),
+            FloatBits(u64),
+            Utf8(&'a str),
+            Timedelta64(i64),
+        }
+
+        let mut seen: HashSet<Key<'_>> = HashSet::new();
+        let mut out = Vec::new();
+        for v in &self.values {
+            if v.is_missing() {
+                continue;
+            }
+            let key = match v {
+                Scalar::Bool(b) => Key::Bool(*b),
+                Scalar::Int64(i) => Key::Int64(*i),
+                Scalar::Float64(f) => {
+                    let norm = if *f == 0.0 { 0.0 } else { *f };
